import{_ as n,o as a,c as t,ag as e}from"./chunks/framework.BbyMWZAR.js";const g=JSON.parse('{"title":"TCP 三次握手、四次挥手与 TCP vs UDP","description":"","frontmatter":{"title":"TCP 三次握手、四次挥手与 TCP vs UDP","difficulty":"hard","tags":["TCP","UDP","三次握手","四次挥手"],"estimate":25},"headers":[],"relativePath":"domains/browser/qa/qa-14-tcp-udp.md","filePath":"domains/browser/qa/qa-14-tcp-udp.md","lastUpdated":1783504823000}'),l={name:"domains/browser/qa/qa-14-tcp-udp.md"};function r(i,s,o,d,p,c){return a(),t("div",null,[...s[0]||(s[0]=[e(`<h1 id="问答-14-高级-tcp-三次握手、四次挥手与-tcp-vs-udp" tabindex="-1">问答 14（高级）：TCP 三次握手、四次挥手与 TCP vs UDP <a class="header-anchor" href="#问答-14-高级-tcp-三次握手、四次挥手与-tcp-vs-udp" aria-label="Permalink to &quot;问答 14（高级）：TCP 三次握手、四次挥手与 TCP vs UDP&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>详细描述 TCP 建连的三次握手和断连的四次挥手。为什么建连是 3 次而挥手要 4 次？TCP 和 UDP 有什么区别，什么场景选哪个？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>三次握手（建立连接）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                       Server</span></span>
<span class="line"><span>   |----- SYN, seq=x --------&gt;|         状态：SYN_SENT</span></span>
<span class="line"><span>   |&lt;--- SYN+ACK, seq=y, ack=x+1 ---|   状态：SYN_RCVD</span></span>
<span class="line"><span>   |----- ACK, ack=y+1 -------&gt;|        双方均为 ESTABLISHED</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>三次握手的核心目的：<strong>双向确认「我能发、你能收；你能发、我能收」</strong> 并同步初始序列号（ISN）。</li><li>第一次：客户端发 SYN，服务端知道客户端能发。</li><li>第二次：服务端发 SYN+ACK，客户端知道服务端能收也能发。</li><li>第三次：客户端发 ACK，服务端知道客户端能收。三次是最少的必要次数。</li><li>如果只两次会有什么问题？服务器无法确认客户端有收到自己的 SYN+ACK，可能出现「历史请求 SYN」被服务端错误地建立连接（半连接混淆）。三次配合 ISN 随机化能有效避免。</li></ul><p><strong>四次挥手（关闭连接）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Client                       Server</span></span>
<span class="line"><span>   |----- FIN, seq=u --------&gt;|          Client: FIN_WAIT_1</span></span>
<span class="line"><span>   |&lt;---- ACK, ack=u+1 ------|           Server: CLOSE_WAIT，Client: FIN_WAIT_2</span></span>
<span class="line"><span>   |     （服务端可能还在发数据）        |</span></span>
<span class="line"><span>   |&lt;---- FIN, seq=w --------|           Server: LAST_ACK</span></span>
<span class="line"><span>   |----- ACK, ack=w+1 ------&gt;|          Client: TIME_WAIT</span></span>
<span class="line"><span>   |     （等待 2MSL）                   |</span></span>
<span class="line"><span>   |                                     |  Server: CLOSED</span></span>
<span class="line"><span>   Client: CLOSED</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><ul><li>为什么挥手是 4 次？ <ul><li>TCP 是<strong>全双工</strong>，两个方向的数据流独立关闭。</li><li>一方发 FIN 表示「我不再发了」，另一方 ACK。</li><li>另一方可能还有数据要发，发完再发自己的 FIN，对方 ACK。因此 FIN 和 ACK <strong>不能合并</strong>，需要 4 次。</li><li>如果对方没有数据要发（比如 keep-alive 到时），FIN 和 ACK 可以合并为 3 次，规范也允许。</li></ul></li><li><strong>TIME_WAIT（2MSL）</strong> 的作用： <ul><li>保证最后一次 ACK 能到达对端（若丢失，对端会重发 FIN，本地还在 TIME_WAIT 能再回 ACK）。</li><li>让本次连接在网络上的残留报文自然消亡，避免污染新连接（相同四元组）。</li></ul></li><li>高并发短连接服务器可能有大量 TIME_WAIT：可开 <code>SO_REUSEADDR</code> / <code>net.ipv4.tcp_tw_reuse</code>，或用长连接、连接池减少握手频率。</li></ul><p><strong>TCP vs UDP</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td>连接</td><td>有连接（握手 / 挥手）</td><td>无连接</td></tr><tr><td>可靠性</td><td>可靠（重传 / 确认 / 排序）</td><td>不可靠（尽力而为）</td></tr><tr><td>顺序</td><td>保证顺序</td><td>不保证</td></tr><tr><td>拥塞控制</td><td>有（慢启动 / 拥塞避免 / 快重传 / 快恢复）</td><td>无</td></tr><tr><td>头部开销</td><td>20 字节以上</td><td>8 字节</td></tr><tr><td>传输速度</td><td>慢一些</td><td>快</td></tr><tr><td>广播 / 多播</td><td>不支持</td><td>支持</td></tr><tr><td>场景</td><td>HTTP、SSH、SMTP、数据库</td><td>DNS、视频 / 音频、游戏、WebRTC、QUIC / HTTP/3</td></tr></tbody></table><p><strong>选型思路</strong></p><ul><li>需要「不能丢、不能乱、要有反馈」→ TCP（如金融交易、文件传输、静态网页）。</li><li>需要「实时、低延迟、可容忍少量丢包」→ UDP（如直播、视频通话、在线游戏）。</li><li>QUIC / HTTP/3 用 UDP 是为了<strong>在用户态自己实现可靠传输</strong>，绕开 TCP 内核栈的限制（队头阻塞、连接迁移不便）。</li></ul><h2 id="追问-1-什么是「半连接队列」和「全连接队列」-和-syn-flood-有什么关系" tabindex="-1">追问 1：什么是「半连接队列」和「全连接队列」？和 SYN Flood 有什么关系？ <a class="header-anchor" href="#追问-1-什么是「半连接队列」和「全连接队列」-和-syn-flood-有什么关系" aria-label="Permalink to &quot;追问 1：什么是「半连接队列」和「全连接队列」？和 SYN Flood 有什么关系？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>服务器为每个 listen socket 维护两个队列： <ul><li><strong>半连接队列（SYN queue）</strong>：收到 SYN、发出 SYN+ACK 但还没收到 ACK 的连接（状态 SYN_RCVD）。</li><li><strong>全连接队列（accept queue）</strong>：三次握手完成、等待应用层 <code>accept()</code> 的连接。</li></ul></li><li><strong>SYN Flood</strong>：攻击者不断发 SYN 但不回 ACK，服务器半连接队列被填满，正常客户端无法建连，服务不可用。</li><li>缓解： <ul><li><code>net.ipv4.tcp_syncookies</code>：不占队列，把连接状态编码进 ISN，收到 ACK 时校验。</li><li>调大 <code>net.core.somaxconn</code>、<code>tcp_max_syn_backlog</code>。</li><li>上游 LB / DDoS 清洗服务提前拦截。</li></ul></li></ul><h2 id="追问-2-nagle-算法和延迟-ack-是什么-为什么有时候会一起造成-200ms-的延迟" tabindex="-1">追问 2：Nagle 算法和延迟 ACK 是什么？为什么有时候会一起造成 200ms 的延迟？ <a class="header-anchor" href="#追问-2-nagle-算法和延迟-ack-是什么-为什么有时候会一起造成-200ms-的延迟" aria-label="Permalink to &quot;追问 2：Nagle 算法和延迟 ACK 是什么？为什么有时候会一起造成 200ms 的延迟？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>Nagle 算法</strong>：为了避免发大量小包，TCP 会把小段数据攒起来，直到「上一段被 ACK」或「攒够 MSS」再发。默认开启，<code>TCP_NODELAY</code> 可关闭。</li><li><strong>Delayed ACK</strong>：接收方为了减少 ACK 数量，会等一段时间再回 ACK，希望搭个便车（下一次响应数据一起发）。等待时间约 40-200ms。</li><li>二者叠加时（一发一收的请求 / 响应模型）：发送方等 ACK 才发下一段小数据，接收方等新数据才回 ACK，双方互等，产生<strong>约 200ms 的额外延迟</strong>。</li><li>表现：小包接口偶尔 200ms 抖动。</li><li>解决：交互式或 RPC 场景关闭 Nagle（<code>TCP_NODELAY = 1</code>）；或改用 HTTP/2 / gRPC 复用连接减少小包。</li></ul><h2 id="追问-3-tcp-的滑动窗口-拥塞控制大致做了什么-为什么-bbr-比-cubic-好" tabindex="-1">追问 3：TCP 的滑动窗口 / 拥塞控制大致做了什么？为什么 BBR 比 CUBIC 好？ <a class="header-anchor" href="#追问-3-tcp-的滑动窗口-拥塞控制大致做了什么-为什么-bbr-比-cubic-好" aria-label="Permalink to &quot;追问 3：TCP 的滑动窗口 / 拥塞控制大致做了什么？为什么 BBR 比 CUBIC 好？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li><strong>流量控制（滑动窗口）</strong>：接收方通告 <code>rwnd</code>（还能接多少字节），发送方不发超过窗口的数据，防止接收方处理不过来。</li><li><strong>拥塞控制</strong>：发送方维护 <code>cwnd</code>，实际发送量取 <code>min(rwnd, cwnd)</code>。 <ul><li><strong>慢启动</strong>：cwnd 指数增长。</li><li><strong>拥塞避免</strong>：达到阈值后线性增长。</li><li><strong>快重传 / 快恢复</strong>：收到 3 个重复 ACK 就认为丢包，快速降窗重传。</li></ul></li><li><strong>CUBIC</strong>（Linux 默认多年）：基于丢包判断拥塞。丢包 = 拥塞。缺点：在有 bufferbloat（缓冲区膨胀）网络里，丢包发生前带宽早就浪费在缓存里，延迟高。</li><li><strong>BBR</strong>（Google，2016）：基于带宽 + RTT 的模型，估算网络最大带宽和最小 RTT，动态调节发送速率。避开对丢包的依赖，在跨国 / 无线 / 高延迟网络上吞吐显著提升，且延迟更低。</li><li>现代 Linux 支持切换：<code>net.ipv4.tcp_congestion_control = bbr</code>。</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/browser/RESOURCES">浏览器 &amp; 网络 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://www.rfc-editor.org/rfc/rfc9293" target="_blank" rel="noreferrer">RFC 9293: TCP</a>：三次握手、四次挥手与可靠传输</li><li><a href="https://hpbn.co/building-blocks-of-tcp/" target="_blank" rel="noreferrer">hpbn.co: Building Blocks of TCP</a>：TCP 拥塞控制与连接管理</li><li><a href="https://www.rfc-editor.org/rfc/rfc768" target="_blank" rel="noreferrer">RFC 768: UDP</a>：UDP 无连接数据报协议</li></ul>`,26)])])}const b=n(l,[["render",r]]);export{g as __pageData,b as default};
